import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface DailyActivity {
  steps: number;
  calories: number;
}

interface WeeklyActivity {
  day: string;
  steps: number;
}

interface FitnessData {
  dailyActivity: DailyActivity;
  weeklyActivity: WeeklyActivity[];
}

export default function Widget() {
  const fitnessData = response.data as FitnessData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F97316', mb: 1 }}>
              Daily Activity
            </Typography>
            <Typography variant="body2" sx={{ color: '#E5E7EB' }}>
              Steps: {fitnessData.dailyActivity.steps.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#E5E7EB' }}>
              Calories: {fitnessData.dailyActivity.calories}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: fitnessData.weeklyActivity.map(day => day.steps),
                  color: '#F97316',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: fitnessData.weeklyActivity.map(day => day.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'steps' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#E5E7EB' }}
              />
              <ChartsYAxis
                axisId="steps"
                tickLabelStyle={{ fontSize: 10, fill: '#E5E7EB' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
